# Cairn bootstrap — the framework described as a Cairn project.
#
# IDs use dotted notation. Top-level is "cairn" (not "cairn.system") — the
# System node's ID is the namespace root, not a label within it.

System Cairn "Map framework with pluggable reconcilers" id "cairn" @framework {

    Container Kernel "Domain-agnostic core" id "cairn.kernel" @kernel {
        path "./src/kernel"

        Module Parser "Parses .blueprint files into a node graph" id "cairn.kernel.parser" {
            path "./src/kernel/parser"
            contract  "./meta/contracts/kernel/parser.md"
            decisions "./meta/decisions/kernel/parser/"
        }

        Module Artefacts "Pluggable artefact type registry" id "cairn.kernel.artefacts" {
            path "./src/kernel/artefacts"
            contract  "./meta/contracts/kernel/artefacts.md"
            decisions "./meta/decisions/kernel/artefacts/"
        }

        Module ReconcilerInterface "Abstract contract for reconcilers" id "cairn.kernel.reconciler" {
            path "./src/kernel/reconciler"
            contract  "./meta/contracts/kernel/reconciler.md"
            decisions "./meta/decisions/kernel/reconciler/"
            research  "./meta/research/kernel/reconciler/"
        }

        Module Reconciliation "Joins blueprint, artefacts, and reconciler output into map" id "cairn.kernel.reconciliation" {
            path "./src/kernel/reconciliation"
            contract "./meta/contracts/kernel/reconciliation.md"
        }

        Module Changes "Change directories, delta semantics, archive" id "cairn.kernel.changes" {
            path "./src/kernel/changes"
            contract  "./meta/contracts/kernel/changes.md"
            decisions "./meta/decisions/kernel/changes/"
        }

        Module Hooks "Commit and task-boundary enforcement" id "cairn.kernel.hooks" {
            path "./src/kernel/hooks"
            contract "./meta/contracts/kernel/hooks.md"
        }

        Module Query "Typed queries over the map" id "cairn.kernel.query" {
            path "./src/kernel/query"
            contract "./meta/contracts/kernel/query.md"
        }

        Module CLI "Primary user surface" id "cairn.kernel.cli" {
            path "./src/kernel/cli"
            contract "./meta/contracts/kernel/cli.md"
        }
    }

    Module CodeReconciler "Tree-sitter-based reconciler for source code" id "cairn.code-reconciler" @reconciler @code {
        path "./src/reconcilers/code"
        contract  "./meta/contracts/reconcilers/code.md"
        decisions "./meta/decisions/reconcilers/code/"
        research  "./meta/research/reconcilers/code/"
    }

    Module Summariser "Optional LLM callout for interface contradictions" id "cairn.summariser" @optional {
        path "./src/summariser"
        contract "./meta/contracts/summariser.md"
    }
}

# Edges. IDs on both sides.
cairn.kernel.cli           -> cairn.kernel.query          "Exposes queries as commands"
cairn.kernel.query         -> cairn.kernel.reconciliation "Reads map"
cairn.kernel.reconciliation -> cairn.kernel.parser        "Consumes parsed blueprint"
cairn.kernel.reconciliation -> cairn.kernel.artefacts     "Validates artefacts"
cairn.kernel.reconciliation -> cairn.kernel.reconciler    "Invokes registered reconcilers"
cairn.code-reconciler      -> cairn.kernel.reconciler     "Implements"
cairn.kernel.changes       -> cairn.kernel.reconciliation "Validates before archive"
cairn.kernel.hooks         -> cairn.kernel.reconciliation "Gates on integrity"
cairn.summariser           -> cairn.kernel.reconciliation "Proposes contract updates on contradictions"
